const items = $input.all();
const collected_at = new Date().toISOString();
return items.map(item => {
  const d = item.json;
  const raw = String(d.date || '');
  const report_date = raw.length === 8
    ? raw.slice(0,4)+'-'+raw.slice(4,6)+'-'+raw.slice(6,8)
    : raw;
  return { json: {
    property_id: '523852603',
    report_date,
    sessions: Number(d.sessions) || 0,
    total_users: Number(d.totalUsers) || 0,
    new_users: Number(d.newUsers) || 0,
    screen_page_views: Number(d.screenPageViews) || 0,
    bounce_rate: Number(d.bounceRate) || 0,
    avg_session_duration: Number(d.averageSessionDuration) || 0,
    engagement_rate: Number(d.engagementRate) || 0,
    engaged_sessions: Number(d.engagedSessions) || 0,
    collected_at
  }};
});

