// If the caller provided a callback_url in the webhook body, forward a completion signal.
// Otherwise return nothing (workflow ends silently).
const callbackUrl = $('Webhook').first().json.body?.callback_url;
if (!callbackUrl) return [];
return [{ json: {
  callback_url: callbackUrl,
  status: 'success',
  refreshed_at: new Date().toISOString(),
  message: 'GA4 pipeline complete'
}}];
